+const COMPONENT_STYLES: &str = r#"
+/* ============================================
+   Header
+   ============================================ */
+
+.header {
+  margin-bottom: 20px;
+  padding-bottom: 16px;
+  border-bottom: 1px solid var(--border);
+}
+
+.header-title {
+  font-size: 1.125rem;
+  font-weight: 600;
+  color: var(--text-primary);
+  margin-bottom: 8px;
+}
+
+.header-meta {
+  display: flex;
+  flex-wrap: wrap;
+  gap: 12px;
+  font-size: 13px;
+  color: var(--text-muted);
+}
+
+.header-meta span {
+  display: inline-flex;
+  align-items: center;
+  gap: 4px;
+}
+
+.header-agent {
+  color: var(--cyan);
+  font-weight: 500;
+}
+
+.header-project {
+  font-family: 'JetBrains Mono', monospace;
+  font-size: 11px;
+  padding: 2px 8px;
+  background: var(--bg-elevated);
+  border-radius: var(--radius-sm);
+}
+
+/* ============================================
+   Toolbar - Glassmorphic
+   ============================================ */
+
+.toolbar {
+  display: flex;
+  align-items: center;
+  gap: 8px;
+  padding: 10px 12px;
+  margin-bottom: 20px;
+  background: oklch(0.14 0.02 260 / 0.8);
+  backdrop-filter: blur(12px);
+  -webkit-backdrop-filter: blur(12px);
+  border: 1px solid oklch(0.3 0.02 260 / 0.3);
+  border-radius: var(--radius-lg);
+  box-shadow: var(--shadow-md);
+}
+
+[data-theme="light"] .toolbar {
+  background: oklch(1 0 0 / 0.85);
+  border-color: oklch(0.9 0.01 260);
+}
+
+.search-wrapper {
+  flex: 1;
+  position: relative;
+}
+
+.search-input {
+  width: 100%;
+  padding: 8px 12px;
+  font-size: 14px;
+  color: var(--text-primary);
+  background: var(--bg-elevated);
+  border: 1px solid var(--border);
+  border-radius: var(--radius-md);
+  outline: none;
+  transition: border-color var(--transition-fast), box-shadow var(--transition-fast);
+}
+
+.search-input::placeholder { color: var(--text-faint); }
+
+.search-input:focus {
+  border-color: var(--cyan);
+  box-shadow: 0 0 0 3px oklch(0.75 0.18 195 / 0.15);
+}
+
+.search-count {
+  position: absolute;
+  right: 12px;
+  top: 50%;
+  transform: translateY(-50%);
+  font-size: 11px;
+  color: var(--text-muted);
+}
+
+.toolbar-btn {
+  display: flex;
+  align-items: center;
+  justify-content: center;
+  width: 36px;
+  height: 36px;
+  background: transparent;
+  border: 1px solid transparent;
+  border-radius: var(--radius-md);
+  color: var(--text-muted);
+  cursor: pointer;
+  transition: all var(--transition-fast);
+}
+
+.toolbar-btn:hover {
+  background: var(--bg-hover);
+  border-color: var(--border);
+  color: var(--text-primary);
+}
+
+.toolbar-btn svg {
+  width: 18px;
+  height: 18px;
+}
+
+/* Theme toggle icons */
+.icon-sun, .icon-moon { transition: opacity var(--transition-fast), transform var(--transition-fast); }
+[data-theme="dark"] .icon-sun { opacity: 0; position: absolute; transform: rotate(90deg); }
+[data-theme="dark"] .icon-moon { opacity: 1; }
+[data-theme="light"] .icon-sun { opacity: 1; }
+[data-theme="light"] .icon-moon { opacity: 0; position: absolute; transform: rotate(-90deg); }
+
+/* ============================================
+   Messages
+   ============================================ */
+
+.conversation {
+  display: flex;
+  flex-direction: column;
+  gap: 12px;
+}
+
+.message {
+  position: relative;
+  padding: 14px 16px;
+  background: var(--bg-surface);
+  border: 1px solid var(--border);
+  border-radius: var(--radius-lg);
+  border-left: 3px solid var(--border);
+  transition: border-color var(--transition-fast), box-shadow var(--transition-fast);
+}
+
+.message:hover {
+  border-color: var(--border-focus);
+  box-shadow: var(--shadow-sm);
+}
+
+/* Role-specific left border colors */
+.message-user { border-left-color: var(--role-user); }
+.message-assistant, .message-agent { border-left-color: var(--role-agent); }
+.message-tool { border-left-color: var(--role-tool); }
+.message-system { border-left-color: var(--role-system); }
+
+.message-header {
+  display: flex;
+  align-items: center;
+  gap: 8px;
+  margin-bottom: 10px;
+  font-size: 13px;
+}
+
+.message-icon {
+  font-size: 14px;
+  line-height: 1;
+}
+
+.message-author {
+  font-weight: 600;
+  font-size: 13px;
+}
+
+.message-user .message-author { color: var(--role-user); }
+.message-assistant .message-author, .message-agent .message-author { color: var(--role-agent); }
+.message-tool .message-author { color: var(--role-tool); }
+.message-system .message-author { color: var(--role-system); }
+
+.message-time {
+  margin-left: auto;
+  font-size: 11px;
+  color: var(--text-faint);
+}
+
+.message-content {
+  font-size: 14px;
+  line-height: 1.65;
+  color: var(--text-secondary);
+}
+
+.message-content > *:first-child { margin-top: 0; }
+.message-content > *:last-child { margin-bottom: 0; }
+
+/* Message link button */
+.message-link {
+  position: absolute;
+  top: 12px;
+  right: 12px;
+  opacity: 0;
+  padding: 4px;
+  background: transparent;
+  border: none;
+  color: var(--text-faint);
+  cursor: pointer;
+  transition: opacity var(--transition-fast), color var(--transition-fast);
+}
+
+.message:hover .message-link { opacity: 1; }
+.message-link:hover { color: var(--cyan); }
+.message-link.copied { color: var(--green); }
+
+/* ============================================
+   Tool Calls - Compact & Elegant
+   ============================================ */
+
+.tool-call {
+  margin-top: 12px;
+  border: 1px solid var(--border);
+  border-radius: var(--radius-md);
+  overflow: hidden;
+  font-size: 13px;
+}
+
+.tool-call summary {
+  display: flex;
+  align-items: center;
+  gap: 8px;
+  padding: 8px 12px;
+  background: var(--bg-elevated);
+  cursor: pointer;
+  list-style: none;
+  transition: background var(--transition-fast);
+}
+
+.tool-call summary::-webkit-details-marker { display: none; }
+.tool-call summary:hover { background: var(--bg-hover); }
+
+.tool-call-icon { font-size: 12px; }
+.tool-call-name { font-weight: 500; color: var(--amber); }
+
+.tool-call-status {
+  margin-left: auto;
+  padding: 2px 8px;
+  font-size: 10px;
+  font-weight: 600;
+  border-radius: var(--radius-sm);
+}
+
+.tool-status-success { background: oklch(0.72 0.19 145 / 0.15); color: var(--green); }
+.tool-status-error { background: oklch(0.65 0.22 25 / 0.15); color: var(--red); }
+.tool-status-pending { background: oklch(0.78 0.16 75 / 0.15); color: var(--amber); }
+
+.tool-call-chevron {
+  font-size: 10px;
+  color: var(--text-faint);
+  transition: transform var(--transition-fast);
+}
+
+.tool-call[open] .tool-call-chevron { transform: rotate(180deg); }
+
+.tool-call-body {
+  padding: 12px;
+  border-top: 1px solid var(--border);
+  background: var(--bg-surface);
+}
+
+.tool-call-section {
+  margin-bottom: 12px;
+}
+.tool-call-section:last-child { margin-bottom: 0; }
+
+.tool-call-label {
+  font-size: 10px;
+  font-weight: 600;
+  text-transform: uppercase;
+  letter-spacing: 0.5px;
+  color: var(--text-faint);
+  margin-bottom: 6px;
+}
+
+.tool-call pre {
+  margin: 0;
+  padding: 10px;
+  font-size: 11px;
+  border-radius: var(--radius-sm);
+}
+
+.tool-truncated {
+  font-size: 11px;
+  color: var(--amber);
+  margin-top: 6px;
+}
+
+/* ============================================
+   Floating Navigation
+   ============================================ */
+
+.floating-nav {
+  position: fixed;
+  bottom: 24px;
+  right: 24px;
+  display: flex;
+  flex-direction: column;
+  gap: 8px;
+  opacity: 0;
+  transform: translateY(20px);
+  transition: opacity var(--transition-normal), transform var(--transition-normal);
+  pointer-events: none;
+  z-index: 100;
+}
+
+.floating-nav.visible {
+  opacity: 1;
+  transform: translateY(0);
+  pointer-events: auto;
+}
+
+.floating-btn {
+  width: 44px;
+  height: 44px;
+  display: flex;
+  align-items: center;
+  justify-content: center;
+  background: var(--bg-surface);
+  border: 1px solid var(--border);
+  border-radius: var(--radius-md);
+  color: var(--text-muted);
+  cursor: pointer;
+  box-shadow: var(--shadow-md);
+  transition: all var(--transition-fast);
+}
+
+.floating-btn:hover {
+  background: var(--bg-elevated);
+  border-color: var(--cyan);
+  color: var(--cyan);
+  box-shadow: var(--shadow-glow-cyan);
+}
+
+.floating-btn svg {
+  width: 20px;
+  height: 20px;
+}
+
+/* ============================================
+   Scroll Progress
+   ============================================ */
+
+.scroll-progress {
+  position: fixed;
+  top: 0;
+  left: 0;
+  height: 3px;
+  background: linear-gradient(90deg, var(--cyan), var(--magenta));
+  z-index: 1000;
+  width: 0;
+  transition: width 0.1s ease;
+}
+
+/* ============================================
+   Keyboard Shortcuts Hint
+   ============================================ */
+
+.shortcuts-hint {
+  position: fixed;
+  bottom: 20px;
+  left: 50%;
+  transform: translateX(-50%) translateY(20px);
+  padding: 10px 16px;
+  background: var(--bg-surface);
+  border: 1px solid var(--border);
+  border-radius: var(--radius-md);
+  font-size: 12px;
+  color: var(--text-muted);
+  opacity: 0;
+  transition: opacity var(--transition-normal), transform var(--transition-normal);
+  z-index: 100;
+  box-shadow: var(--shadow-lg);
+}
+
+.shortcuts-hint.visible {
+  opacity: 1;
+  transform: translateX(-50%) translateY(0);
+}
+
+.shortcuts-hint kbd {
+  display: inline-block;
+  padding: 2px 6px;
+  margin: 0 2px;
+  font-family: 'JetBrains Mono', monospace;
+  font-size: 11px;
+  background: var(--bg-elevated);
+  border: 1px solid var(--border);
+  border-radius: 4px;
+}
+
+/* ============================================
+   Animations
+   ============================================ */
+
+@keyframes fadeIn {
+  from { opacity: 0; transform: translateY(12px); }
+  to { opacity: 1; transform: translateY(0); }
+}
+
+.message {
+  animation: fadeIn 0.3s ease forwards;
+}
+
+@keyframes pulse {
+  0%, 100% { opacity: 1; }
+  50% { opacity: 0.6; }
+}
+
+/* ============================================
+   Accessibility
+   ============================================ */
+
+@media (prefers-reduced-motion: reduce) {
+  *, *::before, *::after {
+    animation-duration: 0.01ms !important;
+    transition-duration: 0.01ms !important;
+  }
+}
+
+:focus-visible {
+  outline: 2px solid var(--cyan);
+  outline-offset: 2px;
+}
+
+/* ============================================
+   Responsive Adjustments
+   ============================================ */
+
+@media (max-width: 640px) {
+  .app-container { padding: 12px; }
+  .header-title { font-size: 1rem; }
+  .toolbar { padding: 8px; }
+  .message { padding: 12px; }
+  .message-content { font-size: 14px; }
+  .tool-call pre { font-size: 10px; padding: 8px; }
+  .floating-nav { bottom: 16px; right: 16px; }
+  .floating-btn { width: 40px; height: 40px; }
+}
+
+/* Hide toolbar on scroll (mobile) */
+.toolbar-hidden {
+  transform: translateY(-100%);
+  opacity: 0;
+  pointer-events: none;
+}
+
+/* ============================================
+   Message Collapse
+   ============================================ */
+
+.message-collapse summary {
+  cursor: pointer;
+  list-style: none;
+}
+
+.message-collapse summary::-webkit-details-marker { display: none; }
+
+.message-preview {
+  color: var(--text-secondary);
+  display: -webkit-box;
+  -webkit-line-clamp: 3;
+  -webkit-box-orient: vertical;
+  overflow: hidden;
+}
+
+.message-expand-hint {
+  display: block;
+  margin-top: 6px;
+  font-size: 12px;
+  font-weight: 500;
+  color: var(--cyan);
+}
+
+.message-collapse[open] .message-expand-hint { display: none; }
+
+.message-expanded { margin-top: 12px; }
+
+/* ============================================
+   Message Animations
+   ============================================ */
+
+@keyframes messageReveal {
+  from {
+    opacity: 0;
+    transform: translateY(24px) scale(0.97);
+  }
+  to {
+    opacity: 1;
+    transform: translateY(0) scale(1);
+  }
+}
+
+.message.in-view {
+  animation: messageReveal 0.4s ease forwards;
+}
+
+/* Keyboard focus state */
+.message.keyboard-focus {
+  outline: 2px solid var(--cyan);
+  outline-offset: 2px;
+  box-shadow: var(--shadow-glow-cyan);
+}
+
+/* ============================================
+   Code Block Copy Button
+   ============================================ */
+
+pre {
+  position: relative;
+}
+
+.copy-code-btn {
+  position: absolute;
+  top: 8px;
+  right: 8px;
+  padding: 4px;
+  background: var(--bg-surface);
+  border: 1px solid var(--border);
+  border-radius: var(--radius-sm);
+  color: var(--text-muted);
+  cursor: pointer;
+  opacity: 0;
+  transition: opacity var(--transition-fast), color var(--transition-fast);
+}
+
+pre:hover .copy-code-btn { opacity: 1; }
+.copy-code-btn:hover { color: var(--cyan); border-color: var(--cyan); }
+.copy-code-btn.copied { color: var(--green); border-color: var(--green); }
+
+/* ============================================
+   Toast Notifications
+   ============================================ */
+
+.toast {
+  padding: 10px 16px;
+  background: var(--bg-surface);
+  border: 1px solid var(--border);
+  border-radius: var(--radius-md);
+  color: var(--text-primary);
+  box-shadow: var(--shadow-lg);
+  font-size: 13px;
+}
+
+.toast-success { border-color: var(--green); }
+.toast-error { border-color: var(--red); }
+
+/* ============================================
+   Touch Ripple Effect
+   ============================================ */
+
+.ripple {
+  position: absolute;
+  border-radius: 50%;
+  background: var(--cyan);
+  opacity: 0.3;
+  transform: scale(0);
+  animation: rippleEffect 0.6s ease-out;
+  pointer-events: none;
+}
+
+@keyframes rippleEffect {
+  to {
+    transform: scale(2.5);
+    opacity: 0;
+  }
+}
+
+/* ============================================
+   Agent-Specific Theming
+   ============================================ */
+
+.agent-claude .message-assistant { border-left-color: oklch(0.7 0.18 50); }
+.agent-codex .message-assistant { border-left-color: oklch(0.7 0.2 145); }
+.agent-cursor .message-assistant { border-left-color: oklch(0.7 0.2 280); }
+.agent-chatgpt .message-assistant { border-left-color: oklch(0.72 0.19 165); }
+.agent-gemini .message-assistant { border-left-color: oklch(0.7 0.2 250); }
+.agent-aider .message-assistant { border-left-color: oklch(0.72 0.16 85); }
+.agent-copilot .message-assistant { border-left-color: oklch(0.7 0.18 200); }
+.agent-cody .message-assistant { border-left-color: oklch(0.68 0.2 340); }
+.agent-windsurf .message-assistant { border-left-color: oklch(0.7 0.2 205); }
+.agent-amp .message-assistant { border-left-color: oklch(0.7 0.18 270); }
+.agent-grok .message-assistant { border-left-color: oklch(0.7 0.22 350); }
+
+/* Print styles */
+@media print {
+  body::before, body::after { display: none; }
+  .toolbar, .floating-nav, .scroll-progress { display: none !important; }
+  .message { break-inside: avoid; }
+  .message-link { display: none; }
+  .copy-code-btn { display: none; }
+}
